def lcs_length(a, b):
    # longest common subsequence length (scaled)
    # But LCS is heavy; we can compute using dynamic programming for moderate length.
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(n):
        prev=0
        for j in range(m):
            tmp=dp[j+1]
            if a[i]==b[j]:
                dp[j+1]=prev+1
            else:
                dp[j+1]=max(dp[j+1], dp[j])
            prev=tmp
    return dp[m]

def sim_ratio(a, b):
    # normalized LCS / max(len(a), len(b))
    a_n = norm_ar(a)
    b_n = norm_ar(b)
    if not a_n or not b_n:
        return 0.0
    l = lcs_length(a_n, b_n)
    return l / max(len(a_n), len(b_n))

