def tokenize(s):
    return norm_ar(s).split()

def token_f1(a, b):
    ta = tokenize(a)
    tb = tokenize(b)
    if not ta or not tb:
        return 0.0
    sa, sb = set(ta), set(tb)
    inter = sa & sb
    if not inter:
        return 0.0
    precision = len(inter)/len(sa)
    recall = len(inter)/len(sb)
    f1 = 2*precision*recall/(precision+recall)
    return f1, precision, recall, len(inter), len(sa), len(sb)

